+#[must_use]
+pub fn checkpoint_reason(
+    cx: &asupersync::Cx,
+    checkpoint: &'static str,
+) -> Option<asupersync::CancelReason> {
+    tracing::debug!(
+        checkpoint,
+        cancel_requested = cx.is_cancel_requested(),
+        "Collector checkpoint"
+    );
+
+    match cx.checkpoint() {
+        Ok(()) => None,
