+            let reason = cx
+                .cancel_reason()
+                .unwrap_or_else(asupersync::CancelReason::parent_cancelled);
+            tracing::debug!(
+                checkpoint,
+                ?reason,
+                error = %error,
+                "Collector checkpoint triggered cancellation"
+            );
+            Some(reason)
+        }
+    }
