+    for y in 0..buf.height() {
+        if y > 0 {
+            out.push('\n');
+        }
+        for x in 0..buf.width() {
+            let cell = buf.get(x, y).expect("buffer cell in bounds");
+            if cell.is_continuation() {
+                continue;
+            }
+            if cell.is_empty() {
+                out.push(' ');
+            } else if let Some(ch) = cell.content.as_char() {
+                out.push(ch);
+            } else {
